-- Core 模块加载
local coreModules = {
  "chat_config", "feedback_config",
  "registry",
  "esp_base", "esp_axe", "esp_runner", "esp_cuirassier",
  "esp_barrel", "esp_lantern", "esp_normal", "esp_driver",
  "esp_player_ctrl", "esp_player_render", "esp_player_events", "esp_fort",
  "hitbox", "killaura", "pvp", "features", "commands", "getitems", "hud",
}

local function loadCoreModule(modName)
  local code2 = MODS["core/" .. modName]
  if not code2 then return nil end
  local preamble = "_G.BFH=_G.BFH or {};_G.BFH.Core=_G.BFH.Core or {};"
  local wrapped = preamble .. code2
  local fn, err = loadstring(wrapped)
  if not fn then warn("[BFH] core/" .. modName .. " 编译失败: " .. tostring(err)); return nil end
  local ok, M = pcall(fn)
  if ok and type(M) == "table" then return M
  elseif not ok then warn("[BFH] core/" .. modName .. " 加载失败: " .. tostring(M)) end
  return nil
end

for _, modName in ipairs(coreModules) do
  local M = loadCoreModule(modName)
  if M then _G.BFH.Core[modName:upper()] = M end
end

-- UI
if MODS.ui then
  local fn, err = loadstring(MODS.ui)
  if fn then local ok, err2 = pcall(fn)
    if not ok then warn("[BFH] ui.lua 加载失败: " .. tostring(err2)) end
  else warn("[BFH] ui.lua 编译失败: " .. tostring(err)) end
end

-- Bridge
if MODS.bridge then
  local fn, err = loadstring(MODS.bridge)
  if fn then local ok, err2 = pcall(fn)
    if not ok then warn("[BFH] bridge.lua 加载失败: " .. tostring(err2)) end
  else warn("[BFH] bridge.lua 编译失败: " .. tostring(err)) end
end

-- 清理
_G.BFH_CLEANUP = function()
  if _G.BFH.Core and _G.BFH.Core.REGISTRY then pcall(_G.BFH.Core.REGISTRY.cleanupAll) end
  if _G._BFH_STOP_ALL then
    for _, fn in ipairs(_G._BFH_STOP_ALL) do pcall(fn) end
    _G._BFH_STOP_ALL = {}
  end
  if _G.BFH.UI and _G.BFH.UI.Destroy then pcall(_G.BFH.UI.Destroy) end
  if _G.BFH.Core then
    for k in pairs(_G.BFH.Core) do
      if k ~= "FEATURES" and k ~= "_th" and k ~= "_vals" then _G.BFH.Core[k] = nil end
    end
  end
  _G.BFH_CLEANUP = nil; _G._BFH_STOP_ALL = nil
end

